import React, { useState ,useEffect } from 'react';
import axios from 'axios';
import ThemeToggle from './ThemeToggle';
import './App.css';

function App() {

  const [activeFileId, setActiveFileId] = useState();

  const [files, setFiles] = useState(() => {

  const savedFiles = localStorage.getItem("files");

  return savedFiles
    ? JSON.parse(savedFiles)
    : [
        {
          id: 1,
          filename: "App.js",
          content: "console.log('Hello World');"
        }
      ];
}); 


const [showCreateInput, setShowCreateInput] = useState(false);

const [newFileName, setNewFileName] = useState("");



  const [code, setCode] = useState(
    'function add(a, b) {\n  return a + b;\n}\n\nadd(1, 3);'
  );

  const [showFiles, setShowFiles] = useState(true);
  const [showAI, setShowAI] = useState(true);

  const [prompt, setPrompt] = useState('');
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);

  
useEffect(() => {
  localStorage.setItem(
    "files",
    JSON.stringify(files)
  );
}, [files]);
  const handleSubmit = async () => {
    console.log('\n========== FRONTEND REQUEST START ==========');
    console.log('📝 Code:', code.substring(0, 100) + '...');
    console.log('💬 Prompt:', prompt);

    if (!code.trim() || !prompt.trim()) {
      console.log('❌ Validation failed');

      setMessages((prev) => [
        ...prev,
        {
          type: 'error',
          text: 'Please enter both code and prompt!'
        }
      ]);
      return;
    }

    const userMessage = {
      type: 'user',
      text: prompt
    };

    setMessages((prev) => [...prev, userMessage]);

    const currentPrompt = prompt;

    setPrompt('');
    setLoading(true);

    const requestPayload = {
      code,
      prompt: currentPrompt
    };

    console.log(
      '📤 Sending to Backend:',
      JSON.stringify(requestPayload, null, 2)
    );

    try {
      const response = await axios.post(
        'http://localhost:5000/api/improve-code',
        requestPayload
      );

      console.log('✅ Response Received');
      console.log('📥 Response Data:', response.data);

      setCode(response.data.improvedCode);

      const aiMessage = {
        type: 'ai',
        text: 'Code updated successfully!',
        code: response.data.improvedCode
      };

      setMessages((prev) => [...prev, aiMessage]);

      console.log('✅ UI Updated');
    } catch (err) {
      console.error('❌ ERROR:', err);

      const errorMessage = {
        type: 'error',
        text: `Error: ${
          err.response?.data?.error || err.message
        }`
      };

      setMessages((prev) => [...prev, errorMessage]);
    } finally {
      setLoading(false);
      console.log(
        '========== FRONTEND REQUEST COMPLETE ==========\n'
      );
    }
  };

  const handleSelection = (e) => {
    const start = e.target.selectionStart;
    const end = e.target.selectionEnd;

    const selectedText = e.target.value.slice(start, end);

    if (selectedText) {
      console.log('Selected Text:', selectedText);
    }
  };
const createFile = () => {
  if (!newFileName.trim()) return;

  const newFile = {
    id: Date.now(),
    filename: newFileName,
    content: ""
  };

  setFiles((prev) => [
    ...prev,
    newFile
  ]);

  setNewFileName("");
  setShowCreateInput(false);
};
const handleFileShow = (filename) => {
     

  const file = files.find(
    (f) => f.filename === filename
  );

  if (file) {
    setCode(file.content);
  }
};

const handelFileSaveNow = ()=>{
   setFiles(prev =>
    prev.map(file =>
      file.id === activeFileId
        ? {
            ...file,
            content: updatedCode
          }
        : file
    )
  );
}

  return (
    <div className="app-container">

      {/* FILE EXPLORER */}
      {showFiles && (
        <div className="file-sidebar">

          <div className="panel-header">
            <h3>📁 File Structure</h3>
          </div>

          <div className="file-tree">
            <div
  style={{
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  }}
>
  <div>📁 src</div>

  <button
  onClick={() => setShowCreateInput(true)}
    className="add-file-btn"
  >
    ➕
  </button>
</div>

  {showCreateInput && (
    <input
      type="text"
      placeholder="File name..."
      value={newFileName}
      onChange={(e) =>
        setNewFileName(e.target.value)
      }
      onKeyDown={(e) => {
        if (e.key === "Enter") {
          createFile();
        }
      }}
    />
  )}

            <div style={{ paddingLeft: '18px' }}>
              {files.map((file, index) => (
                <div
                  key={index}
                  className="file-item"
                  onClick={() =>
                    handleFileShow(file.filename)
                  }
                >
                  📄 {file.filename}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* CODE EDITOR */}
      <div className="editor-panel">

        <div className="panel-header">

          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: '10px'
            }}
          >
            <button
              className="toggle-btn"
              onClick={() =>
                setShowFiles(!showFiles)
              }
            >
              ☰
            </button>

            <button
              className="toggle-btn"
              onClick={() =>
                setShowAI(!showAI)
              }
            >
              🤖
            </button>

            <h3>Code Editor</h3>
          </div>

          <ThemeToggle />
        </div>

        <textarea
          id="inputcode"
          className="code-editor"
          value={code}
          onChange={(e) =>
            setCode(e.target.value)
          }
          onMouseUp={handleSelection}
          placeholder="Write your code here..."
          spellCheck="false"
        />
      </div>

      {/* AI PANEL */}
      {showAI && (
        <div className="chat-panel">

          <div className="panel-header">
            <h3>AI Assistant</h3>

            <button
              className="toggle-btn"
              onClick={() =>
                setShowAI(false)
              }
            >
              ✖
            </button>
          </div>

          <div className="chat-messages">

            {messages.length === 0 ? (
              <div className="empty-chat">
                <p>
                  👋 Hi! I'm your AI code
                  assistant.
                </p>

                <p>
                  Ask me to improve, fix,
                  or explain your code!
                </p>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div
                  key={idx}
                  className={`message ${msg.type}`}
                >
                  <div className="message-label">
                    {msg.type === 'user'
                      ? '👤 You'
                      : msg.type === 'ai'
                      ? '🤖 AI'
                      : '⚠️ Error'}
                  </div>

                  <div className="message-text">
                    {msg.text}
                  </div>
                </div>
              ))
            )}

            {loading && (
              <div className="message ai">
                <div className="message-label">
                  🤖 AI
                </div>

                <div className="message-text loading">
                  Thinking...
                </div>
              </div>
            )}
          </div>

          <div className="chat-input-section">

            <input
              type="text"
              value={prompt}
              onChange={(e) =>
                setPrompt(e.target.value)
              }
              placeholder="Ask AI to improve your code..."
              disabled={loading}
              onKeyDown={(e) => {
                if (
                  e.key === 'Enter' &&
                  !loading
                ) {
                  handleSubmit();
                }
              }}
            />

            <button
              onClick={handleSubmit}
              disabled={
                loading || !prompt.trim()
              }
            >
              {loading ? '⏳' : '🚀'}
            </button>

          </div>
        </div>
      )}
    </div>
  );
}

export default App;
